content.text:
{
  "核心的メッセージ": "問題解決の成果は「解く前」に決まる。目的を明確化し、正しいイシューを定義し、抽象と具体を往復しながら構造化・仮説・検証を短サイクルで回すことで、限られた資源で最大のインパクトを生む。",
  "エグゼクティブ・サマリー（「要約=問い×答え×根拠（Why＝なぜそうなのか？&How=そのためには？）」の形式で、そこさえ見れば本を読まずとも理解できるようにまとめる）": "要約= 問い: なぜ多くの問題解決は成果に結びつかないのか？ × 答え: 問題設定（イシュー選定）と構造化が不十分で、症状対応に終始するから。適切なフレーミングと仮説駆動・可視化・反復学習を組み合わせれば最小努力で最大効果が出る。 × 根拠: Why= 人は前提に縛られ、原因と症状を混同しがちで、制約と目的の階層を見落とす。How= 目的を言語化→イシュー定義→分解・因果・抽象化で構造化→仮説設定→小さく検証→学習して再定義、を短いループで回す。",
  "主要概念の説明（各概念を1〜2文で定義。可能なら一言要約も）": [
    {
      "概念": "問題設定（イシュー定義）",
      "定義": "解くべき問いを選び、境界条件と成功基準を明確にする起点。",
      "一言要約": "問をつくる"
    },
    {
      "概念": "目的と手段の分離",
      "定義": "上位目的を先に据え、既存手段に思考を拘束されない姿勢。",
      "一言要約": "目的先行"
    },
    {
      "概念": "仮説思考",
      "定義": "結論の当たりを先に置き、検証を通じて素早く学ぶアプローチ。",
      "一言要約": "当てに行く"
    },
    {
      "概念": "MECE/ロジックツリー",
      "定義": "重複・漏れなく全体を分解し、論点を構造化する技法。",
      "一言要約": "分けて考える"
    },
    {
      "概念": "因果ループ・システム思考",
      "定義": "相互作用とフィードバックを可視化し、構造から原因を捉える。",
      "一言要約": "つながりを見る"
    },
    {
      "概念": "抽象と具体の往復",
      "定義": "抽象度を上げ下げして一般化と適用を繰り返す。",
      "一言要約": "階層ジャンプ"
    },
    {
      "概念": "バックキャスティング",
      "定義": "望ましい未来像から逆算して現在の打ち手を設計する。",
      "一言要約": "未来起点"
    },
    {
      "概念": "アナロジー思考",
      "定義": "異領域の構造的類似から解のヒントを移植する。",
      "一言要約": "似から学ぶ"
    },
    {
      "概念": "制約条件（TOC）",
      "定義": "全体最適を阻むボトルネックを特定し資源を集中させる。",
      "一言要約": "一点突破"
    },
    {
      "概念": "フレーミング/前提の疑い",
      "定義": "問題の枠組みや隠れた前提を点検・再設定する。",
      "一言要約": "枠を外す"
    },
    {
      "概念": "可視化/KJ法",
      "定義": "情報を外化・整理して関係性と全体像を掴む。",
      "一言要約": "見える化"
    },
    {
      "概念": "実験・プロトタイピング",
      "定義": "小規模に素早く試し、不確実性を削り学習を加速する。",
      "一言要約": "小さく試す"
    }
    ],
  "概念間の関係性や因果関係（箇条書きや簡易図式テキストで可）": [
    "目的明確化 → イシュー定義 → 構造化 → 仮説 → 検証 → 学習 → 再定義（循環）",
    "フレーミング変更 → 問題再定義 → 解決策空間の拡大",
    "抽象↔具体の往復 → アナロジー想起 → 新規解の発見",
    "制約特定（TOC） → 資源集中 → ボトルネック解消 → 全体効果最大化",
    "可視化（KJ/因果図） → 認知負荷低減 → 合意形成加速 → 実行力向上",
    "MECE分解 → 論点明確化 → 仮説精度向上 → 検証効率化"
  ],
  "構造と論理展開（章構成の要点や議論の流れを説明）": [
    "序: 成果が出ない問題解決の失敗パターン（症状対応・前提固定）を提示",
    "基礎: 問題設定の重要性と目的・手段・制約の階層を整理",
    "道具: 構造化・仮説・因果・抽象化・可視化などの思考ツールを体系化",
    "適用: ビジネス/社会課題/日常のケースにツールを組み合わせて適用",
    "プロセス: 目的→イシュー→構造化→仮説→検証→学習の反復ループを設計",
    "終章: 学習する個人・組織への転換と、実践のチェックリストを提示"
  ],
  "重要な引用（原文/要旨＋なぜ重要か1文で）": [
    {
      "原文/要旨": "解くべきは『問題』ではなく『問題の定義』である。",
      "なぜ重要か": "成果を左右するレバーが前段の設定にあることを示す。"
    },
    {
      "原文/要旨": "現象は症状にすぎず、原因は構造の中にある。",
      "なぜ重要か": "対症療法から構造改革へ思考を切り替える指針になる。"
    },
    {
      "原文/要旨": "抽象度を上げ下げすると解決の選択肢が増える。",
      "なぜ重要か": "発想の硬直を避け、他分野からの移植を促す。"
    }
  ],
  "今日できるアクション（読後すぐに15〜30分で実行できるもの）": [
    "身近な不満を10個書き出す",
    "上位目的を3回なぜで掘る",
    "問題文を1行で定義する"
  ],
  "関連書籍（各要素は { \"書名\": \"...\", \"著者\": \"...\", \"関連性\": \"なぜ関連するか\" } の配列）": [
    {
      "書名": "地頭力を鍛える",
      "著者": "細谷 功",
      "関連性": "本質思考・仮説思考など基盤スキルが共通。"
    },
    {
      "書名": "イシューからはじめよ",
      "著者": "安宅 和人",
      "関連性": "問題設定（イシュー選定）の重要性を徹底解説。"
    },
    {
      "書名": "システム思考入門",
      "著者": "ドネラ・H・メドウズ",
      "関連性": "因果ループと構造理解が問題の本質把握に有効。"
    },
    {
      "書名": "問題解決プロフェッショナル 思考と技術",
      "著者": "大前 研一",
      "関連性": "ロジックツリー等の実務的手法が補完関係にある。"
    },
    {
      "書名": "発想法（KJ法）",
      "著者": "川喜田 二郎",
      "関連性": "情報の可視化と統合により構造化を支援。"
    }
  ]
}
